const LRUCache = require('stale-lru-cache');

class MemoryCache {
  /** @type {LRUCache<string>} */
  #cache;

  /**
   * @param {LRUCache.CacheOptions<string>} options
   */
  constructor(options) {
    this.#cache = new LRUCache(options);
  }

  /**
   * @param {string} key
   */
  async get(key) {
    const value = this.#cache.get(key);

    return Promise.resolve(value ? JSON.parse(JSON.stringify(value)) : value);
  }

  /**
   * @param {string} key
   * @param {any} value
   * @param {Parameters<LRUCache<string>['set']>[2]} [maxAge]
   */
  async set(key, value, maxAge) {
    return Promise.resolve(this.#cache.set(key, value, maxAge));
  }
}

module.exports = { MemoryCache };
